"""
Backup script that creates compressed archives of user directories.
Supports multiple compression formats: tar.gz, tar.bz2, zip, 7z
Compatible with Python 2.6+ and Python 3.x
"""

from __future__ import print_function

import os
import sys
import time
import subprocess
import tarfile
import zipfile
import shutil
import logging

try:
    import argparse
except ImportError:
    argparse = None

SUPPORTED_FORMATS = ['tar.gz', 'tar.bz2', 'zip', '7z']

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)


def get_timestamp():
    """Return a timestamp string for naming backup files."""
    return time.strftime('%Y%m%d_%H%M%S')


def get_dir_size(path):
    """Calculate total size of directory in bytes. Works on older Python."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(path):
        for f in filenames:
            fp = os.path.join(dirpath, f)
            try:
                total_size += os.path.getsize(fp)
            except OSError:
                pass
    return total_size


def format_size(size_bytes):
    """Format bytes to human readable string."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "%.2f %s" % (size_bytes, unit)
        size_bytes /= 1024.0
    return "%.2f PB" % size_bytes


def check_7z_available():
    """Check if 7z command line tool is available."""
    try:
        devnull = open(os.devnull, 'w')
        subprocess.call(['7z'], stdout=devnull, stderr=devnull)
        devnull.close()
        return True
    except (OSError, subprocess.CalledProcessError):
        pass
    try:
        devnull = open(os.devnull, 'w')
        subprocess.call(['7za'], stdout=devnull, stderr=devnull)
        devnull.close()
        return '7za'
    except (OSError, subprocess.CalledProcessError):
        return False


def create_tar_gz(source_dir, output_path):
    """Create a tar.gz compressed archive."""
    logger.info("Creating tar.gz archive: %s", output_path)
    try:
        with tarfile.open(output_path, 'w:gz') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
        return True
    except Exception as e:
        logger.error("Failed to create tar.gz archive: %s", str(e))
        # Fallback to command line tar
        logger.info("Attempting fallback using system tar command...")
        try:
            parent_dir = os.path.dirname(os.path.abspath(source_dir))
            base_name = os.path.basename(os.path.abspath(source_dir))
            ret = subprocess.call(
                ['tar', 'czf', output_path, '-C', parent_dir, base_name]
            )
            return ret == 0
        except OSError as e2:
            logger.error("System tar command also failed: %s", str(e2))
            return False


def create_tar_bz2(source_dir, output_path):
    """Create a tar.bz2 compressed archive."""
    logger.info("Creating tar.bz2 archive: %s", output_path)
    try:
        with tarfile.open(output_path, 'w:bz2') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
        return True
    except Exception as e:
        logger.error("Failed to create tar.bz2 archive: %s", str(e))
        # Fallback to command line tar
        logger.info("Attempting fallback using system tar command...")
        try:
            parent_dir = os.path.dirname(os.path.abspath(source_dir))
            base_name = os.path.basename(os.path.abspath(source_dir))
            ret = subprocess.call(
                ['tar', 'cjf', output_path, '-C', parent_dir, base_name]
            )
            return ret == 0
        except OSError as e2:
            logger.error("System tar command also failed: %s", str(e2))
            return False


def create_zip(source_dir, output_path):
    """Create a zip compressed archive."""
    logger.info("Creating zip archive: %s", output_path)
    try:
        source_dir = os.path.abspath(source_dir)
        parent_dir = os.path.dirname(source_dir)
        base_name = os.path.basename(source_dir)

        with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for dirpath, dirnames, filenames in os.walk(source_dir):
                for filename in filenames:
                    file_path = os.path.join(dirpath, filename)
                    arcname = os.path.relpath(file_path, parent_dir)
                    try:
                        zipf.write(file_path, arcname)
                    except (OSError, IOError) as e:
                        logger.warning("Skipping file %s: %s", file_path, str(e))
            # Also add empty directories
            for dirpath, dirnames, filenames in os.walk(source_dir):
                if not filenames and not dirnames:
                    arcname = os.path.relpath(dirpath, parent_dir) + '/'
                    zipf.write(dirpath, arcname)
        return True
    except Exception as e:
        logger.error("Failed to create zip archive: %s", str(e))
        # Fallback to system zip command
        logger.info("Attempting fallback using system zip command...")
        try:
            parent_dir = os.path.dirname(os.path.abspath(source_dir))
            base_name = os.path.basename(os.path.abspath(source_dir))
            original_dir = os.getcwd()
            os.chdir(parent_dir)
            ret = subprocess.call(
                ['zip', '-r', output_path, base_name]
            )
            os.chdir(original_dir)
            return ret == 0
        except OSError as e2:
            logger.error("System zip command also failed: %s", str(e2))
            return False


def create_7z(source_dir, output_path):
    """Create a 7z compressed archive using command line tool."""
    logger.info("Creating 7z archive: %s", output_path)

    available = check_7z_available()
    if not available:
        logger.error(
            "7z/7za command not found. Please install p7zip or p7zip-full."
        )
        logger.info("On Debian/Ubuntu: sudo apt-get install p7zip-full")
        logger.info("On CentOS/RHEL: sudo yum install p7zip p7zip-plugins")
        return False

    cmd_name = available if isinstance(available, str) else '7z'

    try:
        source_dir = os.path.abspath(source_dir)
        ret = subprocess.call(
            [cmd_name, 'a', '-t7z', '-mx=5', output_path, source_dir]
        )
        return ret == 0
    except OSError as e:
        logger.error("Failed to create 7z archive: %s", str(e))
        return False


def validate_source_directory(source_dir):
    """Validate that the source directory exists and is readable."""
    if not os.path.exists(source_dir):
        logger.error("Source directory does not exist: %s", source_dir)
        return False
    if not os.path.isdir(source_dir):
        logger.error("Source path is not a directory: %s", source_dir)
        return False
    if not os.access(source_dir, os.R_OK):
        logger.error("Source directory is not readable: %s", source_dir)
        return False
    return True


def validate_output_directory(output_dir):
    """Validate/create output directory."""
    if not os.path.exists(output_dir):
        try:
            os.makedirs(output_dir)
            logger.info("Created output directory: %s", output_dir)
        except OSError as e:
            logger.error("Cannot create output directory %s: %s", output_dir, str(e))
            return False
    if not os.access(output_dir, os.W_OK):
        logger.error("Output directory is not writable: %s", output_dir)
        return False
    return True


def create_backup(source_dir, fmt, output_dir=None, backup_name=None):
    """
    Create a backup archive of the specified directory.

    Args:
        source_dir: Path to the directory to back up
        fmt: Compression format (tar.gz, tar.bz2, zip, 7z)
        output_dir: Directory to store the backup (default: current directory)
        backup_name: Custom name for the backup file (default: auto-generated)

    Returns:
        Path to created backup file, or None on failure
    """
    source_dir = os.path.abspath(source_dir)

    if not validate_source_directory(source_dir):
        return None

    if fmt not in SUPPORTED_FORMATS:
        logger.error(
            "Unsupported format: %s. Supported formats: %s",
            fmt, ', '.join(SUPPORTED_FORMATS)
        )
        return None

    if output_dir is None:
        output_dir = os.getcwd()

    if not validate_output_directory(output_dir):
        return None

    # Generate backup filename
    dir_name = os.path.basename(source_dir)
    timestamp = get_timestamp()

    if backup_name:
        base_filename = backup_name
    else:
        base_filename = "backup_%s_%s" % (dir_name, timestamp)

    # Determine extension
    ext_map = {
        'tar.gz': '.tar.gz',
        'tar.bz2': '.tar.bz2',
        'zip': '.zip',
        '7z': '.7z',
    }
    extension = ext_map[fmt]
    output_path = os.path.join(output_dir, base_filename + extension)

    # Check if file already exists
    if os.path.exists(output_path):
        logger.warning("Output file already exists: %s", output_path)
        output_path = os.path.join(
            output_dir,
            base_filename + '_' + str(int(time.time())) + extension
        )
        logger.info("Using alternative name: %s", output_path)

    # Log source directory info
    dir_size = get_dir_size(source_dir)
    logger.info("Source directory: %s", source_dir)
    logger.info("Source size: %s", format_size(dir_size))
    logger.info("Output format: %s", fmt)
    logger.info("Output path: %s", output_path)

    # Create the backup
    start_time = time.time()

    format_handlers = {
        'tar.gz': create_tar_gz,
        'tar.bz2': create_tar_bz2,
        'zip': create_zip,
        '7z': create_7z,
    }

    handler = format_handlers[fmt]
    success = handler(source_dir, output_path)

    elapsed = time.time() - start_time

    if success and os.path.exists(output_path):
        archive_size = os.path.getsize(output_path)
        if dir_size > 0:
            ratio = (1.0 - float(archive_size) / float(dir_size)) * 100.0
        else:
            ratio = 0.0
        logger.info("Backup completed successfully!")
        logger.info("Archive size: %s", format_size(archive_size))
        logger.info("Compression ratio: %.1f%%", ratio)
        logger.info("Time elapsed: %.2f seconds", elapsed)
        logger.info("Backup saved to: %s", output_path)
        return output_path
    else:
        logger.error("Backup failed!")
        # Clean up partial file if it exists
        if os.path.exists(output_path):
            try:
                os.remove(output_path)
                logger.info("Cleaned up partial archive file.")
            except OSError:
                pass
        return None


def verify_archive(archive_path, fmt):
    """Verify the integrity of a created archive."""
    logger.info("Verifying archive integrity: %s", archive_path)

    if not os.path.exists(archive_path):
        logger.error("Archive file not found: %s", archive_path)
        return False

    try:
        if fmt in ('tar.gz', 'tar.bz2'):
            mode = 'r:gz' if fmt == 'tar.gz' else 'r:bz2'
            with tarfile.open(archive_path, mode) as tar:
                members = tar.getmembers()
                logger.info("Archive contains %d entries.", len(members))
            return True

        elif fmt == 'zip':
            with zipfile.ZipFile(archive_path, 'r') as zipf:
                bad_files = zipf.testzip()
                if bad_files is not None:
                    logger.error("Corrupt file in archive: %s", bad_files)
                    return False
                entries = zipf.namelist()
                logger.info("Archive contains %d entries.", len(entries))
            return True

        elif fmt == '7z':
            available = check_7z_available()
            if not available:
                logger.warning("Cannot verify 7z archive: 7z command not found.")
                return True  # Skip verification
            cmd_name = available if isinstance(available, str) else '7z'
            ret = subprocess.call(
                [cmd_name, 't', archive_path],
                stdout=open(os.devnull, 'w'),
                stderr=open(os.devnull, 'w')
            )
            if ret == 0:
                logger.info("7z archive verification passed.")
                return True
            else:
                logger.error("7z archive verification failed.")
                return False

    except Exception as e:
        logger.error("Archive verification failed: %s", str(e))
        return False


def parse_args_manual(argv):
    """Manual argument parsing for systems without argparse (Python 2.6)."""
    import getopt

    usage = """Usage: %s [OPTIONS] SOURCE_DIR FORMAT

Create compressed backup of a directory.

Arguments:
  SOURCE_DIR    Directory to back up
  FORMAT        Compression format: tar.gz, tar.bz2, zip, 7z

Options:
  -o, --output-dir DIR   Output directory (default: current directory)
  -n, --name NAME        Custom backup name (without extension)
  -v, --verify           Verify archive after creation
  -l, --list-formats     List supported formats
  -h, --help             Show this help message
""" % os.path.basename(argv[0])

    output_dir = None
    backup_name = None
    verify = False

    try:
        opts, args = getopt.getopt(
            argv[1:],
            'o:n:vlh',
            ['output-dir=', 'name=', 'verify', 'list-formats', 'help']
        )
    except getopt.GetoptError as e:
        print("Error: %s" % str(e))
        print(usage)
        sys.exit(1)

    for opt, val in opts:
        if opt in ('-h', '--help'):
            print(usage)
            sys.exit(0)
        elif opt in ('-o', '--output-dir'):
            output_dir = val
        elif opt in ('-n', '--name'):
            backup_name = val
        elif opt in ('-v', '--verify'):
            verify = True
        elif opt in ('-l', '--list-formats'):
            print("Supported formats: %s" % ', '.join(SUPPORTED_FORMATS))
            sys.exit(0)

    if len(args) < 2:
        print("Error: SOURCE_DIR and FORMAT are required.")
        print(usage)
        sys.exit(1)

    source_dir = args[0]
    fmt = args[1]

    return source_dir, fmt, output_dir, backup_name, verify


def parse_args_argparse(argv):
    """Parse arguments using argparse (Python 2.7+)."""
    parser = argparse.ArgumentParser(
        description='Create compressed backup of a directory.',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s /home/user tar.gz
  %(prog)s /home/user zip -o /backups
  %(prog)s /home/user tar.bz2 -n my_backup -v
  %(prog)s /var/www 7z -o /mnt/backup_drive
"""
    )

    parser.add_argument(
        'source_dir',
        help='Directory to back up'
    )
    parser.add_argument(
        'format',
        choices=SUPPORTED_FORMATS,
        help='Compression format: %s' % ', '.join(SUPPORTED_FORMATS)
    )
    parser.add_argument(
        '-o', '--output-dir',
        default=None,
        help='Output directory (default: current directory)'
    )
    parser.add_argument(
        '-n', '--name',
        default=None,
        help='Custom backup name (without extension)'
    )
    parser.add_argument(
        '-v', '--verify',
        action='store_true',
        default=False,
        help='Verify archive integrity after creation'
    )
    parser.add_argument(
        '-l', '--list-formats',
        action='store_true',
        default=False,
        help='List supported compression formats and exit'
    )

    args = parser.parse_args(argv[1:])

    if args.list_formats:
        print("Supported formats: %s" % ', '.join(SUPPORTED_FORMATS))
        sys.exit(0)

    return args.source_dir, args.format, args.output_dir, args.name, args.verify


def main():
    """Main entry point."""
    if argparse is not None:
        source_dir, fmt, output_dir, backup_name, verify = parse_args_argparse(sys.argv)
    else:
        source_dir, fmt, output_dir, backup_name, verify = parse_args_manual(sys.argv)

    logger.info("=" * 60)
    logger.info("Backup Script Started")
    logger.info("=" * 60)

    # Create the backup
    result = create_backup(
        source_dir=source_dir,
        fmt=fmt,
        output_dir=output_dir,
        backup_name=backup_name
    )

    if result is None:
        logger.error("Backup creation failed!")
        sys.exit(1)

    # Verify if requested
    if verify:
        logger.info("-" * 40)
        is_valid = verify_archive(result, fmt)
        if not is_valid:
            logger.error("Archive verification FAILED!")
            sys.exit(2)
        logger.info("Archive verification PASSED.")

    logger.info("=" * 60)
    logger.info("Backup completed: %s", result)
    logger.info("=" * 60)

    sys.exit(0)


if __name__ == '__main__':
    main()